CREATE PROCEDURE test_amazon_describe()
{
  DECLARE access_key VARCHAR(50);
  DECLARE sec_token VARCHAR(50);
  DECLARE amis ANY;
  access_key := 'AKIAABCDEFGHIJKLMN';
  sec_token := 'XYZ1234567890';
  amis := xtree_doc(DB.DBA.AMAZON_DESCRIBE_INSTANCES(access_key, sec_token));
  SELECT id FROM instances WHERE bif:contains(tags, xpath_eval('/DescribeInstancesResponse/reservationSet/item/instancesSet/item', amis, 0));
};
